import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.Culc7SYV.js";const m=JSON.parse('{"title":"Coach","description":"","frontmatter":{},"headers":[],"relativePath":"Coach.md","filePath":"Coach.md","lastUpdated":1773806339000}'),s={name:"Coach.md"};function i(n,e,l,h,d,c){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="coach" tabindex="-1">Coach <a class="header-anchor" href="#coach" aria-label="Permalink to &quot;Coach&quot;">​</a></h1><p>Last modified: 18/03/2026</p><h2 id="what-coach-does" tabindex="-1">What Coach Does <a class="header-anchor" href="#what-coach-does" aria-label="Permalink to &quot;What Coach Does&quot;">​</a></h2><p>Coach helps you build focused study plans for exams and tests. You select the notes, folders, or groups you want to study, set an exam date, and Coach creates a personalised daily plan with targets for both flashcards and note reviews.</p><h2 id="creating-a-plan" tabindex="-1">Creating a Plan <a class="header-anchor" href="#creating-a-plan" aria-label="Permalink to &quot;Creating a Plan&quot;">​</a></h2><ol><li>Open <strong>Coach</strong> from the sidebar.</li><li>Click <strong>Get started</strong> (or <strong>+ New plan</strong> if you already have one).</li><li><strong>Topics</strong> — search and select the notes, folders, groups, or entire vault you want to include.</li><li><strong>Schedule</strong> — set your exam date and choose an intensity level (relaxed, balanced, or aggressive).</li><li><strong>Review</strong> — check the summary and click <strong>Start plan</strong>.</li></ol><p>Coach calculates daily flashcard and note targets based on how much material is in scope, how many days remain, and your chosen intensity.</p><h2 id="daily-progress" tabindex="-1">Daily Progress <a class="header-anchor" href="#daily-progress" aria-label="Permalink to &quot;Daily Progress&quot;">​</a></h2><p>Each plan shows a progress bar for the current day — how many flashcards and notes you have completed versus your daily target. A remaining line tells you exactly what is left for today.</p><p>From the plan card you can:</p><ul><li><strong>Study flashcards</strong> — opens the reviewer scoped to your plan material.</li><li><strong>Review notes</strong> — opens note review scoped to your plan.</li><li><strong>Generate practice test</strong> — creates an exam-style test from your plan content.</li></ul><h2 id="how-health-scores-work" tabindex="-1">How Health Scores Work <a class="header-anchor" href="#how-health-scores-work" aria-label="Permalink to &quot;How Health Scores Work&quot;">​</a></h2><p>The <strong>Study Plan Health</strong> panel shows three bars: Flashcards, Notes, and Exam. Each is a 0–100 score.</p><h3 id="flashcard-health" tabindex="-1">Flashcard Health <a class="header-anchor" href="#flashcard-health" aria-label="Permalink to &quot;Flashcard Health&quot;">​</a></h3><p>Flashcard health blends two things:</p><ul><li><strong>Mastery of studied cards</strong> — for every flashcard you have already reviewed, Coach reads its memory strength from the spaced repetition algorithm (FSRS). Cards you know well contribute a high score; cards whose memory has faded pull it down.</li><li><strong>Time feasibility for unstudied cards</strong> — for cards you have not yet started, Coach asks: &quot;Given the daily target and the days remaining, is there enough time to get through them all before the exam?&quot; If there is plenty of runway, this portion scores well. If the exam is tomorrow and hundreds of new cards remain, it scores poorly.</li></ul><p>The final flashcard health is a weighted blend of these two. Material you have actually studied and retained counts at full weight; material you <em>could</em> study in the time remaining is discounted slightly, because having the capacity to study something is not the same as knowing it.</p><h3 id="note-health" tabindex="-1">Note Health <a class="header-anchor" href="#note-health" aria-label="Permalink to &quot;Note Health&quot;">​</a></h3><p>Note health works the same way — reviewed notes weighted by retention, plus time feasibility for notes you have not yet reviewed.</p><h3 id="exam-health" tabindex="-1">Exam Health <a class="header-anchor" href="#exam-health" aria-label="Permalink to &quot;Exam Health&quot;">​</a></h3><p>Exam health is simply a weighted average of your flashcard and note health scores, giving a single at-a-glance number for overall readiness.</p><h3 id="what-the-labels-mean" tabindex="-1">What the Labels Mean <a class="header-anchor" href="#what-the-labels-mean" aria-label="Permalink to &quot;What the Labels Mean&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Label</th><th>Meaning</th></tr></thead><tbody><tr><td>Ready</td><td>Strong mastery and comfortable time margin</td></tr><tr><td>On track</td><td>Good progress, no immediate concern</td></tr><tr><td>At risk</td><td>Some gaps — either fading retention or tight schedule</td></tr><tr><td>Behind</td><td>Significant gaps in mastery or insufficient time remaining</td></tr></tbody></table><h2 id="how-the-readiness-chart-works" tabindex="-1">How the Readiness Chart Works <a class="header-anchor" href="#how-the-readiness-chart-works" aria-label="Permalink to &quot;How the Readiness Chart Works&quot;">​</a></h2><p>The <strong>Exam Readiness</strong> chart tracks a 0–100 readiness score from plan creation through to exam day.</p><ul><li>The <strong>solid line</strong> shows your actual readiness over past days. Each point combines how much of the material you have studied and how well you remember it (via the spaced repetition memory model), blended with time feasibility for the material you have not yet reached.</li><li>The <strong>dashed line</strong> projects your readiness into the future, assuming you follow your daily targets from today onward. It models how existing card memories will naturally decay over time, offset by the reviews you are expected to complete, which restore memory strength.</li></ul><p>On day one of a feasible plan with plenty of time, readiness starts moderately high — you have not learned anything yet, but there is ample runway to cover the material. As the exam approaches, the feasibility window shrinks, so readiness increasingly depends on what you have actually studied and how well you remember it.</p><p>If you fall behind your targets, the actual line diverges from the projection, making it easy to spot when you need to catch up.</p><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ul><li><strong>Start early</strong> — the further out your exam date, the more forgiving the daily targets.</li><li><strong>Study consistently</strong> — short daily sessions maintain memory strength better than cramming.</li><li><strong>Check the health bars</strong> — if flashcard health is dropping, it usually means old cards need review; if note health is low, you have unreviewed notes piling up.</li><li><strong>Adjust intensity</strong> — if targets feel unsustainable, edit the plan and switch to a more relaxed intensity.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./Scheduling">Scheduling</a></li><li><a href="./Flashcards">Flashcards</a></li><li><a href="./Tests">Tests</a></li><li><a href="./Study-Sessions">Study Sessions</a></li></ul>',32)])])}const y=a(s,[["render",i]]);export{m as __pageData,y as default};
